import React from "react";
import { useSelector } from "react-redux";
import { Card, Col, Row, Statistic } from "antd";

const toDrivingMode = (disengageType) => {
  switch (disengageType) {
    case "DISENGAGE_MANUAL":
      return "MANUAL";
    case "DISENGAGE_NONE":
      return "AUTO";
    case "DISENGAGE_EMERGENCY":
      return "DISENGAGED";
    case "DISENGAGE_AUTO_STEER_ONLY":
      return "AUTO STEER";
    case "DISENGAGE_AUTO_SPEED_ONLY":
      return "AUTO SPEED";
    case "DISENGAGE_CHASSIS_ERROR":
      return "CHASSIS ERROR";
    case "DISENGAGE_REMOTE":
      return "REMOTE";
    case "DISENGAGE_MEDIAN":
      return "MEDIAN";
    case "DISENGAGE_MAINTENANCE":
      return "MAINTENANCE";
    default:
      return "UNKNOWN";
  }
};

const RealtimeApp = () => {
  const vehicleStatus = useSelector((state) => state.realtime.vehicleStatus);
  const adVersion = useSelector((state) => state.realtime.adVersion);
  const currentMap = useSelector((state) => state.realtime.currentMap);
  const carSpeed = useSelector(
    (state) => state.sendPoint.autoDrivingCars.speed
  );
  const drivingMode = useSelector(
    (state) => state.sendPoint.autoDrivingCars.disengageType
  );

  return (
    <div>
      <Row gutter={[16, 16]} wrap>
        <Col span={12}>
          <Card variant="borderless">
            <Statistic
              title="CPU"
              value={vehicleStatus?.cpu * 100}
              precision={2}
              valueStyle={{ color: "#3f8600" }}
              suffix="%"
            />
          </Card>
        </Col>
        <Col span={12}>
          <Card variant="borderless">
            <Statistic
              title="Disk"
              value={vehicleStatus?.disk * 100}
              precision={2}
              valueStyle={{ color: "#3f8600" }}
              suffix="%"
            />
          </Card>
        </Col>
        <Col span={12}>
          <Card variant="borderless">
            <Statistic
              title="Memory"
              value={vehicleStatus?.memory * 100}
              precision={2}
              valueStyle={{ color: "#3f8600" }}
              suffix="%"
            />
          </Card>
        </Col>
        <Col span={12}>
          <Card variant="borderless">
            <Statistic
              title="AD Statu"
              value={vehicleStatus?.status?.toUpperCase()}
              valueStyle={{ color: "#3f8600" }}
            />
          </Card>
        </Col>
        <Col span={12}>
          <Card variant="borderless">
            <Statistic
              title="Speed"
              value={carSpeed && (carSpeed * 3.6).toFixed(2)}
              precision={2}
              valueStyle={{ color: "#3f8600" }}
              suffix="km/h"
            />
          </Card>
        </Col>
        <Col span={12}>
          <Card variant="borderless">
            <Statistic
              title="Mode Type"
              value={toDrivingMode(drivingMode)}
              valueStyle={{ color: "#3f8600" }}
            />
          </Card>
        </Col>
        <Col span={12}>
          <Card variant="borderless">
            <Statistic
              title="Current Map"
              value={currentMap}
              valueStyle={{ color: "#3f8600" }}
            />
          </Card>
        </Col>
        <Col span={12}>
          <Card variant="borderless">
            <Statistic
              title="AD Version"
              value={adVersion?.toUpperCase()}
              valueStyle={{ color: "#3f8600" }}
            />
          </Card>
        </Col>
      </Row>
    </div>
  );
};

export default RealtimeApp;
